request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?messageName ?orgId WHERE {
  ?message a bboExt:Message ;
           bbo:name ?messageName ;
           tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?messageName)), LCASE("staff acecss user")))

  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model a bboExt:Model ;
         bbo:name ?modelName .
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org tai:organizationId ?orgId . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?name ?type ?orgId WHERE {
  {
    ?elem bbo:name ?name .
  }
  UNION
  {
    ?elem rdfs:comment ?name .
  }
  UNION
  {
    ?elem rdfs:label ?name .
  }
  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("staff acecss user")) ||
    CONTAINS(LCASE(STR(?name)), "acecss") ||
    CONTAINS(LCASE(STR(?name)), "acec") ||
    CONTAINS(LCASE(STR(?name)), "access")
  )

  ?elem a ?type .
  OPTIONAL { ?elem tai:belongsTo ?choreo . ?choreo tai:belongsTo ?defs . ?defs tai:belongsTo ?model . ?model tai:belongsTo ?org . ?org tai:organizationId ?orgId . }
}
LIMIT 25
